/**
 * Functions
 */
void fmacfw_iram_init(void)
{
    uint32_t *src, *dst = (uint32_t *)__fmacfw_rom_start__;
    uint32_t idx, wd_cnt;
    #if defined(CFG_BWMODE)
    src = (uint32_t *)fmacfw_8800m40_bwmode;
    wd_cnt = sizeof(fmacfw_8800m40_bwmode) / sizeof(uint32_t);
    #else
    src = (uint32_t *)fmacfw_8800m40;
    wd_cnt = sizeof(fmacfw_8800m40) / sizeof(uint32_t);
    #endif
    for (idx = 0; idx < wd_cnt; idx++) {
        *dst = *src;
        dst++;
        src++;
    }
}
